      // Add the new item to the start of the array
      newItems.unshift(nextItem);

      // Cycle through the mock data
      this.currentIndex = (this.currentIndex + 1) % this.allActivities.length;

      return newItems;
    });
  }

  ngOnDestroy() {
    if (this.intervalId) {
      clearInterval(this.intervalId);
    }
  }
}

