import { inject, Injectable } from '@angular/core';
import { HttpClient } from '@angular/common/http';
import { forkJoin, map, Observable } from 'rxjs';

// --- Interfaces for API responses ---
interface DynamicGlobalProperties {
  total_vesting_fund_hive: string;
  total_vesting_shares: string;
  hbd_interest_rate: number;
  total_payout_hbd_legacy: string; // Not a real property, for combining data
  total_payout_hive_legacy: string; // Not a real property, for combining data
  total_author_payout_hbd: string; // Not a real property, for combining data
  total_curator_payout_hbd: string; // Not a real property, for combining data
  total_comment_payout_hbd: string; // Not a real property, for combining data
  head_block_number: number;
  num_accounts: number;
}

interface MedianHistoryPrice {
  base: string; // e.g., "1.234 HBD"
  quote: string; // e.g., "1.000 HIVE"
}

interface RewardFund {
    reward_balance: string; // e.g., "12345.678 HIVE"
}

interface JsonRpcResponse<T> {
  result: T;
}

// --- Combined Stats Interface for the Component ---
export interface HiveStats {
    hivePrice: number;
    totalAccounts: number;
    transactions: number;
    rewardPool: number;
    dailyActiveUsers: number; // This will be a mocked value
    totalPayouts: number; // Mocked for now
}

@Injectable({ providedIn: 'root' })
export class HiveService {
  private http = inject(HttpClient);
  private readonly API_URL = 'https://api.hive.blog';

  private createRequest<T>(method: string, params: any[] = []): Observable<T> {
    const body = {
      jsonrpc: '2.0',
      method,
      params,
      id: 1,
    };
    return this.http.post<JsonRpcResponse<T>>(this.API_URL, body).pipe(map(response => response.result));
  }

  getBlockchainStats(): Observable<HiveStats> {
    return forkJoin({
      globals: this.createRequest<DynamicGlobalProperties>('condenser_api.get_dynamic_global_properties'),
      price: this.createRequest<MedianHistoryPrice>('condenser_api.get_current_median_history_price'),
      rewardFund: this.createRequest<RewardFund>('condenser_api.get_reward_fund', ['post'])
    }).pipe(
      map(({ globals, price, rewardFund }) => {
        const hivePrice = parseFloat(price.base.split(' ')[0]) / parseFloat(price.quote.split(' ')[0]);
        const rewardPool = parseFloat(rewardFund.reward_balance.split(' ')[0]) * hivePrice;

        return {
          hivePrice,
          rewardPool,
          totalAccounts: globals.num_accounts,
          transactions: globals.head_block_number * 20, // Rough estimation
          dailyActiveUsers: 15000 + Math.floor(Math.random() * 1000), // Mocked for display
          totalPayouts: 150000000 + Math.floor(Math.random() * 1000000), // Mocked for display
        };
      })
    );
  }
}

import { ChangeDetectionStrategy, Component, inject, OnInit, signal } from '@angular/core';
import { HiveService, HiveStats } from '../../services/hive.service';
import { catchError, of } from 'rxjs';

@Component({
  selector: 'app-stats',
  templateUrl: './stats.component.html',
  changeDetection: ChangeDetectionStrategy.OnPush,
})
export class StatsComponent implements OnInit {
  private hiveService = inject(HiveService);

  stats = signal<HiveStats | null>(null);
  isLoading = signal(true);
  error = signal<string | null>(null);

  ngOnInit() {
    this.hiveService.getBlockchainStats().pipe(
      catchError(err => {
        console.error('Failed to fetch Hive stats:', err);
        this.error.set('Could not load blockchain data. Please try again later.');
        this.isLoading.set(false);
        return of(null);
      })
    ).subscribe(data => {
      if (data) {
        this.stats.set(data);
      }
      this.isLoading.set(false);
    });
  }

  formatNumber(value: number | undefined): string {
    if (value === undefined) return '...';
    return value.toLocaleString('en-US', { maximumFractionDigits: 0 });
  }

  formatCurrency(value: number | undefined, maximumFractionDigits = 0): string {
    if (value === undefined) return '...';
    return value.toLocaleString('en-US', {
      style: 'currency',
      currency: 'USD',
      maximumFractionDigits
    });
  }
}

