import { GoogleGenAI } from '@google/genai';
import type { Handler, HandlerEvent } from "@netlify/functions";

// This system instruction is now securely on the backend.
const systemInstruction = `You are an expert on the Hive blockchain, tasked with explaining it to complete beginners who have no prior knowledge of cryptocurrency.
      - Your tone must be friendly, encouraging, and highly accessible.
      - Avoid overly technical jargon. If you must use a technical term (like 'blockchain' or 'decentralized'), explain it in a very simple analogy.
      - Focus on the benefits for content creators, communities, and regular users. Emphasize concepts like ownership of content, earning rewards, and censorship resistance.
      - Keep responses concise and to the point.
      - Your goal is to make Hive sound exciting, innovative, and easy to get started with.
    `;

const handler: Handler = async (event: HandlerEvent) => {
  // Only allow POST requests
  if (event.httpMethod !== 'POST') {
    return {
      statusCode: 405,
      body: JSON.stringify({ error: 'Method Not Allowed' }),
    };
  }

  // Securely get the API key from Netlify's environment variables
  const apiKey = process.env.API_KEY;
  if (!apiKey) {
    console.error('API_KEY environment variable not set.');
    return {
      statusCode: 500,
      body: JSON.stringify({ error: 'API key is not configured on the server.' }),
    };
  }

  try {
    const body = JSON.parse(event.body || '{}');
    const prompt = body.prompt;

    // Basic validation
    if (!prompt || typeof prompt !== 'string' || prompt.trim().length === 0) {
      return {
        statusCode: 400,
        body: JSON.stringify({ error: 'A question prompt is required.' }),
      };
    }

    // Add a simple length check to prevent overly long (and costly) prompts
    if (prompt.length > 500) {
      return {
        statusCode: 400,
        body: JSON.stringify({ error: 'Your question is too long. Please keep it under 500 characters.' }),
      };
    }

    const ai = new GoogleGenAI({ apiKey });
    const response = await ai.models.generateContent({
        model: 'gemini-2.5-flash',
        contents: prompt,
        config: {
          systemInstruction: systemInstruction,
          temperature: 0.7,
        },
    });

    const text = response.text;

    return {
      statusCode: 200,
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ answer: text }),
    };

  } catch (error) {
    console.error('Error in ask-ai function:', error);
    return {
      statusCode: 500,
      body: JSON.stringify({ error: 'An error occurred while communicating with the AI service.' }),
    };
  }
};

export { handler };

import { inject, Injectable } from '@angular/core';
import { HttpClient, HttpErrorResponse } from '@angular/common/http';
import { firstValueFrom, map } from 'rxjs';

@Injectable({
  providedIn: 'root'
})
export class GeminiService {
  private http = inject(HttpClient);
  // This URL points to the Netlify function, using the redirect from netlify.toml
  private readonly apiUrl = '/api/ask-ai';

  async getHiveExplanation(prompt: string): Promise<string> {
    try {
      // The service now sends a simple HTTP request to our own backend
      const response$ = this.http.post<{ answer: string }>(this.apiUrl, { prompt }).pipe(
        map(response => response.answer)
      );
      // Convert the Observable to a Promise for the component
      return await firstValueFrom(response$);
    } catch (error) {
      console.error('Error calling backend proxy:', error);

      // Try to extract a more specific error message from the proxy's response
      if (error instanceof HttpErrorResponse && error.error?.error) {
         throw new Error(error.error.error);
      }

      // Fallback generic error
      throw new Error('The AI assistant is currently unavailable. Please try again later.');
    }
  }
}

import { ChangeDetectionStrategy, Component, inject, signal } from '@angular/core';
import { FormsModule } from '@angular/forms';
import { GeminiService } from '../../services/gemini.service';

@Component({
  selector: 'app-hive-explainer',
  templateUrl: './hive-explainer.component.html',
  imports: [FormsModule],
  changeDetection: ChangeDetectionStrategy.OnPush,
})
export class HiveExplainerComponent {
  private geminiService = inject(GeminiService);

  question = signal('');
  answer = signal('');
  isLoading = signal(false);
  error = signal('');

  predefinedQuestions = [
    'What can I do on Hive?',
    'How do I earn rewards?',
    'Is Hive like other social media platforms?',
    'What are Hive communities?'
  ];

  async askQuestion(prompt: string) {
    if (!prompt || this.isLoading()) {
      return;
    }

    this.question.set(prompt);
    this.isLoading.set(true);
    this.error.set('');
    this.answer.set('');

    try {
      const result = await this.geminiService.getHiveExplanation(prompt);
      this.answer.set(result);
    } catch (e: any) {
      this.error.set(e.message || 'Sorry, something went wrong. Please try again.');
      console.error(e);
    } finally {
      this.isLoading.set(false);
    }
  }

  handleFormSubmit(event: Event) {
    event.preventDefault();
    this.askQuestion(this.question());
  }
}
